class Solution:
    def magicalString(self, n: int) -> int:
        if n == 0: return 0
        s = [1, 2, 2]
        i = 2
        while len(s) < n:
            s.extend([s[-1] % 2 + 1] * s[i])
            i += 1
        return sum(s[:n])

