class Solution {
public:
    int magicalString(int n) {
        if(!n) return 0;
        vector<int> s={1,2,2}; int i=2, ans=0;
        while((int)s.size()<n){
            int rep=s[i], val=s.back()==1?2:1;
            while(rep--) s.push_back(val);
            i++;
        }
        for(int j=0;j<n;j++) ans+=s[j]==1;
        return ans;
    }
};

