int magicalString(int n) {
    if(!n) return 0;
    int* s=malloc((n+100)*sizeof(int)); int sz=3, i=2;
    s[0]=1;s[1]=2;s[2]=2;
    while(sz<n){
        int rep=s[i], val=s[sz-1]==1?2:1;
        while(rep--) s[sz++]=val;
        i++;
    }
    int ans=0; for(int j=0;j<n;j++) if(s[j]==1) ans++;
    free(s); return ans;
}
